@namespace sv_e3aaacdbc73643259349d88087063e34.Components.Pages.Settings
@using sv_e3aaacdbc73643259349d88087063e34.Services
@inject ISettingsService SettingsService

<div class="settings-section security-section">
    <h2>Security</h2>

    @if (_loading)
    {
        <p>Loading security settings...</p>
    }
    else
    {
        <!-- Change Password Panel -->
        <div class="expandable-panel">
            <button class="panel-header" @onclick="() => _passwordPanelOpen = !_passwordPanelOpen">
                <span>Change Password</span>
                <span class="panel-toggle">@(_passwordPanelOpen ? "▼" : "▶")</span>
            </button>

            @if (_passwordPanelOpen)
            {
                <div class="panel-body">
                    <div class="form-group">
                        <label for="currentPassword">Current Password</label>
                        <input id="currentPassword" type="password" @bind="_currentPassword" />
                    </div>
                    <div class="form-group">
                        <label for="newPassword">New Password</label>
                        <input id="newPassword" type="password" @bind="_newPassword" />
                    </div>
                    <div class="form-group">
                        <label for="confirmPassword">Confirm Password</label>
                        <input id="confirmPassword" type="password" @bind="_confirmPassword" />
                    </div>
                    @if (_passwordError is not null)
                    {
                        <div class="toast error">@_passwordError</div>
                    }
                    @if (_passwordSuccess is not null)
                    {
                        <div class="toast success">@_passwordSuccess</div>
                    }
                    <button class="btn-primary" @onclick="ChangePasswordAsync">Update Password</button>
                </div>
            }
        </div>

        <!-- Two-Factor Authentication -->
        <div class="two-factor-section">
            <h3>Two-Factor Authentication</h3>
            <div class="status-row">
                <span class="status-indicator @(_twoFactorEnabled ? "enabled" : "disabled")">
                    @(_twoFactorEnabled ? "● Enabled" : "○ Disabled")
                </span>
                <label class="toggle-label">
                    <input type="checkbox" @bind="_twoFactorEnabled" />
                    <span>Enable 2FA</span>
                </label>
            </div>
            @if (_lastPasswordChange.HasValue)
            {
                <p class="text-muted">Last password change: @_lastPasswordChange.Value.ToString("MMMM dd, yyyy")</p>
            }
        </div>

        <!-- Active Sessions -->
        <div class="sessions-section">
            <h3>Active Sessions</h3>
            <table class="sessions-table">
                <thead>
                    <tr>
                        <th>Device</th>
                        <th>Location</th>
                        <th>Last Active</th>
                        <th>Actions</th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var session in _sessions)
                    {
                        <tr>
                            <td>@session.Device</td>
                            <td>@session.Location</td>
                            <td>@session.LastActive.ToString("g")</td>
                            <td>
                                @if (session != _sessions.FirstOrDefault())
                                {
                                    <button class="btn-danger btn-sm" @onclick="() => ConfirmRevoke(session)">
                                        Revoke
                                    </button>
                                }
                                else
                                {
                                    <span class="text-muted">Current</span>
                                }
                            </td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>

        <!-- Revoke Confirmation Dialog -->
        @if (_sessionToRevoke is not null)
        {
            <div class="modal-overlay">
                <div class="modal-dialog">
                    <h4>Confirm Session Revoke</h4>
                    <p>Are you sure you want to revoke the session on <strong>@_sessionToRevoke.Device</strong> from <strong>@_sessionToRevoke.Location</strong>?</p>
                    <div class="modal-actions">
                        <button class="btn-danger" @onclick="RevokeSessionAsync">Revoke</button>
                        <button class="btn-secondary" @onclick="() => _sessionToRevoke = null">Cancel</button>
                    </div>
                </div>
            </div>
        }
    }
</div>

@code {
    private bool _loading = true;
    private bool _passwordPanelOpen;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private string? _passwordError;
    private string? _passwordSuccess;
    private bool _twoFactorEnabled;
    private DateTime? _lastPasswordChange;
    private List<ActiveSession> _sessions = new();
    private ActiveSession? _sessionToRevoke;

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetSecuritySettingsAsync();
        _twoFactorEnabled = settings.TwoFactorEnabled;
        _lastPasswordChange = settings.LastPasswordChange;
        _sessions = settings.Sessions;
        _loading = false;
    }

    private async Task ChangePasswordAsync()
    {
        _passwordError = null;
        _passwordSuccess = null;

        if (string.IsNullOrWhiteSpace(_newPassword))
        {
            _passwordError = "New password cannot be empty.";
            return;
        }

        if (_newPassword != _confirmPassword)
        {
            _passwordError = "New password and confirmation do not match.";
            return;
        }

        try
        {
            await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
            _passwordSuccess = "Password updated successfully!";
            _currentPassword = "";
            _newPassword = "";
            _confirmPassword = "";
        }
        catch (Exception ex)
        {
            _passwordError = ex.Message;
        }
    }

    private void ConfirmRevoke(ActiveSession session)
    {
        _sessionToRevoke = session;
    }

    private async Task RevokeSessionAsync()
    {
        if (_sessionToRevoke is null) return;

        await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
        _sessions.Remove(_sessionToRevoke);
        _sessionToRevoke = null;
    }
}

@namespace sv_e3aaacdbc73643259349d88087063e34.Components.Pages.Settings
@using sv_e3aaacdbc73643259349d88087063e34.Services
@inject ISettingsService SettingsService

<div class="settings-section appearance-section">
    <h2>Appearance</h2>

    @if (_loading)
    {
        <p>Loading appearance settings...</p>
    }
    else
    {
        <!-- Theme Selector -->
        <div class="form-group">
            <label>Theme</label>
            <div class="radio-group">
                @foreach (var theme in new[] { "Light", "Dark", "System" })
                {
                    <label class="radio-label">
                        <input type="radio" name="theme" value="@theme"
                               checked="@(_theme == theme)"
                               @onchange="() => _theme = theme" />
                        <span>@theme</span>
                    </label>
                }
            </div>
        </div>

        <!-- Font Size Selector -->
        <div class="form-group">
            <label>Font Size</label>
            <div class="radio-group">
                @foreach (var size in new[] { "Small", "Medium", "Large" })
                {
                    <label class="radio-label">
                        <input type="radio" name="fontSize" value="@size"
                               checked="@(_fontSize == size)"
                               @onchange="() => _fontSize = size" />
                        <span>@size</span>
                    </label>
                }
            </div>
        </div>

        <!-- Language Dropdown -->
        <div class="form-group">
            <label for="language">Language</label>
            <select id="language" @bind="_language">
                <option value="en">English</option>
                <option value="es">Spanish</option>
                <option value="fr">French</option>
                <option value="de">German</option>
                <option value="ja">Japanese</option>
                <option value="zh">Chinese</option>
            </select>
        </div>

        <!-- Compact Mode Toggle -->
        <div class="form-group">
            <label class="toggle-label">
                <input type="checkbox" @bind="_compactMode" />
                <span>Compact Mode</span>
            </label>
        </div>

        <!-- Live Preview -->
        <div class="preview-area @GetPreviewClasses()">
            <h4>Preview</h4>
            <p class="preview-text">This is how your content will look with the selected settings.</p>
            <button class="preview-button">Sample Button</button>
        </div>

        <div class="form-actions">
            <button class="btn-primary" @onclick="SaveAsync">Save</button>
        </div>

        @if (_successMessage is not null)
        {
            <div class="toast success">@_successMessage</div>
        }
    }
</div>

@code {
    private string _theme = "System";
    private string _fontSize = "Medium";
    private string _language = "en";
    private bool _compactMode;
    private bool _loading = true;
    private string? _successMessage;

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetAppearanceAsync();
        _theme = settings.Theme;
        _fontSize = settings.FontSize;
        _language = settings.Language;
        _compactMode = settings.CompactMode;
        _loading = false;
    }

    private string GetPreviewClasses()
    {
        var theme = _theme.ToLowerInvariant();
        var size = _fontSize.ToLowerInvariant();
        var compact = _compactMode ? "compact" : "";
        return $"preview-{theme} preview-font-{size} {compact}".Trim();
    }

    private async Task SaveAsync()
    {
        var settings = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
        await SettingsService.SaveAppearanceAsync(settings);
        _successMessage = "Appearance saved!";
        _ = ClearMessageAfterDelay();
    }

    private async Task ClearMessageAfterDelay()
    {
        await Task.Delay(3000);
        _successMessage = null;
        await InvokeAsync(StateHasChanged);
    }
}

