{"file_text": ".settings-dashboard {
    display: flex;
    min-height: calc(100vh - 4rem);
    gap: 0;
}

/* Sidebar */
.settings-sidebar {
    width: 220px;
    background: #f8f9fa;
    border-right: 1px solid #dee2e6;
    padding: 1.5rem 0;
    flex-shrink: 0;
}

.sidebar-title {
    padding: 0 1.5rem;
    margin-bottom: 1rem;
    font-size: 1.1rem;
    color: #495057;
}

.sidebar-nav {
    list-style: none;
    padding: 0;
    margin: 0;
}

.sidebar-nav li button {
    display: block;
    width: 100%;
    padding: 0.75rem 1.5rem;
    border: none;
    background: none;
    text-align: left;
    font-size: 0.95rem;
    color: #495057;
    cursor: pointer;
    transition: background 0.15s, color 0.15s;
}

.sidebar-nav li button:hover {
    background: #e9ecef;
}

.sidebar-nav li.active button {
    background: #0d6efd;
    color: #fff;
    font-weight: 500;
}

/* Main content area */
.settings-content {
    flex: 1;
    padding: 2rem;
    max-width: 800px;
}

.settings-section h2 {
    margin-bottom: 1.5rem;
    padding-bottom: 0.5rem;
    border-bottom: 1px solid #dee2e6;
}

/* Form elements */
.form-group {
    margin-bottom: 1.25rem;
}

.form-group label {
    display: block;
    margin-bottom: 0.4rem;
    font-weight: 500;
    color: #212529;
}

.form-group input[type="text"],
.form-group input[type="email"],
.form-group input[type="password"],
.form-group textarea,
.form-group select {
    width: 100%;
    padding: 0.5rem 0.75rem;
    border: 1px solid #ced4da;
    border-radius: 0.375rem;
    font-size: 0.95rem;
}

.form-group textarea {
    resize: vertical;
}

.form-actions {
    margin-top: 1.5rem;
    display: flex;
    gap: 0.75rem;
}

/* Buttons */
.btn-primary {
    padding: 0.5rem 1.25rem;
    background: #0d6efd;
    color: #fff;
    border: none;
    border-radius: 0.375rem;
    cursor: pointer;
    font-size: 0.9rem;
}

.btn-primary:hover {
    background: #0b5ed7;
}

.btn-secondary {
    padding: 0.5rem 1.25rem;
    background: #6c757d;
    color: #fff;
    border: none;
    border-radius: 0.375rem;
    cursor: pointer;
    font-size: 0.9rem;
}

.btn-secondary:hover {
    background: #5c636a;
}

.btn-danger {
    padding: 0.5rem 1.25rem;
    background: #dc3545;
    color: #fff;
    border: none;
    border-radius: 0.375rem;
    cursor: pointer;
    font-size: 0.9rem;
}

.btn-danger:hover {
    background: #bb2d3b;
}

.btn-sm {
    padding: 0.25rem 0.75rem;
    font-size: 0.8rem;
}

/* Toast messages */
.toast {
    margin-top: 1rem;
    padding: 0.75rem 1rem;
    border-radius: 0.375rem;
    font-size: 0.9rem;
}

.toast.success {
    background: #d1e7dd;
    color: #0f5132;
    border: 1px solid #badbcc;
}

.toast.error {
    background: #f8d7da;
    color: #842029;
    border: 1px solid #f5c2c7;
}

/* Toggle labels */
.toggle-group {
    display: flex;
    flex-direction: column;
    gap: 0.75rem;
    margin-bottom: 1.5rem;
}

.toggle-label {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    cursor: pointer;
}

.toggle-label input[type="checkbox"] {
    width: 1.1rem;
    height: 1.1rem;
}

/* Avatar */
.avatar-preview {
    margin-bottom: 1.5rem;
    text-align: center;
}

.avatar-image {
    width: 100px;
    height: 100px;
    border-radius: 50%;
    object-fit: cover;
    border: 2px solid #dee2e6;
}

.avatar-url {
    margin-top: 0.5rem;
    font-size: 0.8rem;
    color: #6c757d;
    word-break: break-all;
}

/* Muted channels */
.muted-channels h3 {
    font-size: 1rem;
    margin-bottom: 0.75rem;
}

.channel-list {
    list-style: none;
    padding: 0;
}

.channel-list li {
    padding: 0.4rem 0;
}

.channel-list li label {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    cursor: pointer;
}

