    justify-content: space-between;
    align-items: center;
    width: 100%;
    padding: 0.75rem 1rem;
    border: none;
    background: #f8f9fa;
    cursor: pointer;
    font-size: 0.95rem;
    font-weight: 500;
    border-radius: 0.375rem;
}

.panel-header:hover {
    background: #e9ecef;
