}

.preview-button {
    margin-top: 0.5rem;
    padding: 0.4rem 1rem;
    border: 1px solid #ced4da;
    border-radius: 0.25rem;
    background: #0d6efd;
    color: #fff;
    cursor: default;
}

.text-muted {
    color: #6c757d;
    font-size: 0.9rem;
}
