@namespace sv_e3aaacdbc73643259349d88087063e34.Components.Pages.Settings

<nav class="settings-sidebar">
    <h3 class="sidebar-title">Settings</h3>
    <ul class="sidebar-nav">
        @foreach (var section in Sections)
        {
            <li class="@(section == ActiveSection ? "active" : "")">
                <button @onclick="() => OnSectionChanged.InvokeAsync(section)">
                    @section
                </button>
            </li>
        }
    </ul>
</nav>

@code {
    [Parameter] public string ActiveSection { get; set; } = "Profile";
    [Parameter] public EventCallback<string> OnSectionChanged { get; set; }

    private static readonly string[] Sections = ["Profile", "Notifications", "Security", "Appearance"];
}

@namespace sv_e3aaacdbc73643259349d88087063e34.Components.Pages.Settings
@using sv_e3aaacdbc73643259349d88087063e34.Services
@inject ISettingsService SettingsService

<div class="settings-section profile-section">
    <h2>Profile</h2>

    @if (_loading)
    {
        <p>Loading profile...</p>
    }
    else
    {
        <div class="avatar-preview">
            <img src="@_avatarUrl" alt="Avatar" class="avatar-image" />
            <p class="avatar-url">@_avatarUrl</p>
        </div>

        <div class="form-group">
            <label for="displayName">Display Name</label>
            <input id="displayName" type="text" @bind="_displayName" />
        </div>

        <div class="form-group">
            <label for="email">Email</label>
            <input id="email" type="email" @bind="_email" />
        </div>

        <div class="form-group">
            <label for="bio">Bio</label>
            <textarea id="bio" @bind="_bio" rows="4"></textarea>
        </div>

        <div class="form-actions">
            <button class="btn-primary" @onclick="SaveAsync">Save Changes</button>
            <button class="btn-secondary" @onclick="Discard">Discard Changes</button>
        </div>

        @if (_successMessage is not null)
        {
            <div class="toast success">@_successMessage</div>
        }
    }
</div>

@code {
    private string _displayName = "";
    private string _email = "";
    private string _avatarUrl = "";
    private string _bio = "";
    private UserProfile? _savedProfile;
    private bool _loading = true;
    private string? _successMessage;

    protected override async Task OnInitializedAsync()
    {
        var profile = await SettingsService.GetProfileAsync();
        ApplyProfile(profile);
        _savedProfile = profile;
        _loading = false;
    }

    private void ApplyProfile(UserProfile profile)
    {
        _displayName = profile.DisplayName;
        _email = profile.Email;
        _avatarUrl = profile.AvatarUrl;
        _bio = profile.Bio;
    }

    private async Task SaveAsync()
    {
        var profile = new UserProfile(_displayName, _email, _avatarUrl, _bio);
        await SettingsService.SaveProfileAsync(profile);
        _savedProfile = profile;
        _successMessage = "Profile saved successfully!";
        _ = ClearMessageAfterDelay();
    }

    private void Discard()
    {
        if (_savedProfile is not null)
        {
            ApplyProfile(_savedProfile);
        }
        _successMessage = null;
    }

    private async Task ClearMessageAfterDelay()
    {
        await Task.Delay(3000);
        _successMessage = null;
        await InvokeAsync(StateHasChanged);
    }
}

