@namespace sv_e3aaacdbc73643259349d88087063e34.Components.Pages.Settings
@using sv_e3aaacdbc73643259349d88087063e34.Services
@inject ISettingsService SettingsService

<div class="settings-section notifications-section">
    <h2>Notifications</h2>

    @if (_loading)
    {
        <p>Loading notification preferences...</p>
    }
    else
    {
        <div class="toggle-group">
            <label class="toggle-label">
                <input type="checkbox" @bind="_emailNotifications" />
                <span>Email Notifications</span>
            </label>

            <label class="toggle-label">
                <input type="checkbox" @bind="_pushNotifications" />
                <span>Push Notifications</span>
            </label>

            <label class="toggle-label">
                <input type="checkbox" @bind="_weeklyDigest" />
                <span>Weekly Digest</span>
            </label>
        </div>

        <div class="muted-channels">
            <h3>Muted Channels</h3>
            @if (_allChannels.Count == 0)
            {
                <p class="text-muted">No channels available.</p>
            }
            else
            {
                <ul class="channel-list">
                    @foreach (var channel in _allChannels)
                    {
                        <li>
                            <label>
                                <input type="checkbox"
                                       checked="@_mutedChannels.Contains(channel)"
                                       @onchange="e => ToggleChannel(channel, (bool)e.Value!)" />
                                <span>@channel</span>
                            </label>
                        </li>
                    }
                </ul>
            }
        </div>

        <div class="form-actions">
            <button class="btn-primary" @onclick="SaveAsync">Save Preferences</button>
        </div>

        @if (_successMessage is not null)
        {
            <div class="toast success">@_successMessage</div>
        }
    }
</div>

@code {
    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private HashSet<string> _mutedChannels = new();
    private List<string> _allChannels = new();
    private bool _loading = true;
    private string? _successMessage;

    protected override async Task OnInitializedAsync()
    {
        var prefs = await SettingsService.GetNotificationPrefsAsync();
        _emailNotifications = prefs.EmailNotifications;
        _pushNotifications = prefs.PushNotifications;
        _weeklyDigest = prefs.WeeklyDigest;
        _mutedChannels = new HashSet<string>(prefs.MutedChannels);
        // Use the muted channels as the known channel list
        _allChannels = prefs.MutedChannels.ToList();
        _loading = false;
    }

    private void ToggleChannel(string channel, bool muted)
    {
        if (muted)
            _mutedChannels.Add(channel);
        else
            _mutedChannels.Remove(channel);
    }

    private async Task SaveAsync()
    {
        var prefs = new NotificationPrefs(_emailNotifications, _pushNotifications, _weeklyDigest, _mutedChannels.ToList());
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        _successMessage = "Preferences saved!";
        _ = ClearMessageAfterDelay();
    }

    private async Task ClearMessageAfterDelay()
    {
        await Task.Delay(3000);
        _successMessage = null;
        await InvokeAsync(StateHasChanged);
    }
}

