namespace sv_e3aaacdbc73643259349d88087063e34.Services;

/// <summary>
/// Stub implementation for development/testing. Replace with a real implementation.
/// </summary>
public class InMemorySettingsService : ISettingsService
{
    private UserProfile _profile = new("Jane Doe", "jane@example.com", "https://i.pravatar.cc/150?u=jane", "Software developer and open source enthusiast.");
    private NotificationPrefs _notifications = new(true, false, true, new List<string> { "general", "random", "announcements", "off-topic" });
    private SecuritySettings _security = new(true, DateTime.UtcNow.AddDays(-30), new List<ActiveSession>
    {
        new("s1", "Chrome on Windows", "New York, US", DateTime.UtcNow.AddMinutes(-5)),
        new("s2", "Safari on iPhone", "New York, US", DateTime.UtcNow.AddHours(-2)),
        new("s3", "Firefox on Linux", "London, UK", DateTime.UtcNow.AddDays(-1))
    });
    private AppearanceSettings _appearance = new("System", "Medium", "en", false);

    public Task<UserProfile> GetProfileAsync() => Task.FromResult(_profile);

    public Task SaveProfileAsync(UserProfile profile)
    {
        _profile = profile;
        return Task.CompletedTask;
    }

    public Task<NotificationPrefs> GetNotificationPrefsAsync() => Task.FromResult(_notifications);

    public Task SaveNotificationPrefsAsync(NotificationPrefs prefs)
    {
        _notifications = prefs;
        return Task.CompletedTask;
    }

    public Task<SecuritySettings> GetSecuritySettingsAsync() => Task.FromResult(_security);

    public Task ChangePasswordAsync(string currentPassword, string newPassword)
    {
        if (string.IsNullOrWhiteSpace(currentPassword))
            throw new InvalidOperationException("Current password is required.");
        _security = _security with { LastPasswordChange = DateTime.UtcNow };
        return Task.CompletedTask;
    }

    public Task RevokeSessionAsync(string sessionId)
    {
        var updated = _security.Sessions.Where(s => s.Id != sessionId).ToList();
        _security = _security with { Sessions = updated };
        return Task.CompletedTask;
    }

    public Task<AppearanceSettings> GetAppearanceAsync() => Task.FromResult(_appearance);

    public Task SaveAppearanceAsync(AppearanceSettings settings)
    {
        _appearance = settings;
        return Task.CompletedTask;
    }
}

